----------------------------------------------------------------
---沿着路线行走到其他地板
---@class LFightIdlePathActor
local LFightIdlePathActor = LxClass("LFightIdlePathActor",nil)
----------------------------------------------------------------
-----------------------------------------------------------------
function LFightIdlePathActor:LFightIdlePathActor(obj,manager)
	---@type LFightIdleObject
	self._obj = obj

	self._manager = manager

	self._isJumping = false

	self._isWaitJumping = false

	self._isWaitChangeBoard = false

	self._isPathing = false

	self._targetBoardRefId = nil

	self._nowIndex = 0
	self._pathLinks = nil

	self._nextBoardPaths = nil

	self._nextBoardRefId = nil

	self._endTime = 0
end

function LFightIdlePathActor:OnRun(time)
	if not self._isPathing then return end
	if self._endTime < time then
		if self._isWaitJumping then
			self:StartJumping(self._jumpDownPos)
		else
			self:JumpOnNextBoard()

			if self._bWaitStopPathing then
				self:StopPathing()
			else
				self:NextPath()
			end
		end
	end
end

--跳到的地块上面，修改areaIndex参数，修改boardRef参数，修改pathIndex参数
function LFightIdlePathActor:JumpOnNextBoard()
	if not self._isWaitChangeBoard then return end
	self._isWaitChangeBoard = false

	local areaIndex = self._nextAreaIndex
	local boardRefId = self._nextBoardRefId
	local paths = self._nextBoardPaths

	local obj = self._obj


	local pathIndex = 1

	local objCtrl = self._manager:GetObjCtrl()
	local teamList = objCtrl:GetTeamBySide(obj:GetSide())

	--已经使用的地板路线
	local dicBoardPathUsed = {}

	for k,v in ipairs(teamList) do
		local checkBoardRefId = v:GetBoardRefId()
		if checkBoardRefId == boardRefId then
			dicBoardPathUsed[v:GetPathIndex()] = true
		end
	end
	local idlePathIndexList = {}
	for k,v in ipairs(paths) do
		if not dicBoardPathUsed[k] then
			table.insert(idlePathIndexList,k)
		end
	end

	if #idlePathIndexList > 0 then
		pathIndex = idlePathIndexList[1]
	else
		pathIndex = LFightIdleConst.RandInteger(#paths)
	end

	local path = paths[pathIndex]

	local minPos,maxPos = path.left,path.right

	obj:SetAreaIndex(areaIndex)
	obj:SetBoardRefId(boardRefId)

	obj:SetPathIndex(pathIndex)
	obj:SetPathData(minPos,maxPos)

	local pos = obj:GetPosition()
	pos.y = minPos.y
	obj:SetPosition(pos)
end

function LFightIdlePathActor:ResetJumpData(shadowMapData)
	local links = self._pathLinks
	for k,v in ipairs(self._pathLinks) do
		links[k] = shadowMapData[v] or v
	end

	local nextBoardRefId = links[self._nowIndex]
	local nextBoardRef = self._manager:GetBoardRef(nextBoardRefId)
	self._nextAreaIndex = self._manager:GetAreaCtrl():GetAreaIndexByAreaId(nextBoardRef.areaId)
	self._nextBoardRefId = nextBoardRefId
	local paths = nextBoardRef.paths
	self._nextBoardPaths = paths
end

function LFightIdlePathActor:StartPathing(toBoardRefId,toPos)
	self._isPathing = true
	self._bWaitStopPathing = false

	local nowBoardRefId = self._obj:GetBoardRefId()
	if nowBoardRefId == toBoardRefId then
		self:StopPathing()
		return
	end

	self._targetBoardRefId = toBoardRefId

	local _,links = self._manager:GetPathCtrl():FindPath(nowBoardRefId,toBoardRefId,self._obj:GetPosition(),toPos)

	self._pathLinks = links

	self._obj:SetTargetBoardRefId(toBoardRefId)

	--links 第一个放的是  当前boardRefId
	self._nowIndex = 1
	self:NextPath()
end

function LFightIdlePathActor:NextPath()
	local links = self._pathLinks
	if not links then
		self:StopPathing()
		return
	end
	local index = self._nowIndex + 1
	if index > #links then
		self:StopPathing()
		return
	end

	self._nowIndex = index

	local nextBoardRefId = links[index]
	self._nextBoardRefId = nextBoardRefId
	local nextBoardRef = self._manager:GetBoardRef(nextBoardRefId)
	self._nextAreaIndex = self._manager:GetAreaCtrl():GetAreaIndexByAreaId(nextBoardRef.areaId)
	local paths = nextBoardRef.paths
	self._nextBoardPaths = paths
	local nextPath = paths[1]
	local nextMinPos,nextMaxPos = nextPath.left,nextPath.right

	local obj = self._obj
	local nowMinPos,nowMaxPos = obj:GetPathData()
	local nowPos = obj:GetPosition()

	local movePos,jumpDownPos = self:CalcMoveAndJump(nowPos,nowMinPos,nowMaxPos,nextMinPos,nextMaxPos)
	self._jumpDownPos = jumpDownPos

	self._isJumping = false
	self._isWaitChangeBoard = true

	if movePos then
		self._isWaitJumping = true
		self:StartMove(movePos)
	else
		self:StartJumping(jumpDownPos)
	end
end

function LFightIdlePathActor:StartMove(movePos)
	local obj = self._obj
	local speed = obj:GetMoveSpeed()
	local btObjectView = obj:GetBtObjectView()

	local pos = obj:GetPosition()

	local time = Mathf.Abs(movePos.x - pos.x) / speed * 100

	btObjectView:StartMove(movePos,time)

	obj:PlayRunAni()

	obj:ChangeDirToPos(movePos)

	self._endTime = self:GetTime() + time
end

function LFightIdlePathActor:StartJumping(jumpDownPos)
	self._isJumping = true
	self._isWaitJumping = false

	local obj = self._obj

	local btObjectView = obj:GetBtObjectView()
	local pos = obj:GetPosition()

	local speed = 3

	local bDown = pos.y >= jumpDownPos.y

	obj:PlayJumpAni(bDown)

	local topY = jumpDownPos.y + 1.0
	if bDown then
		if pos.y - jumpDownPos.y > 0.15 then
			topY = pos.y + 0.5
		end
	end

	local disY = Mathf.Abs(pos.y - jumpDownPos.y)
	local disX = Mathf.Abs(pos.x - jumpDownPos.x)
	local dis = Mathf.Max(disX,disY)

	local time = dis / speed
	if time > 0.8 then time = 0.8 end
	if time < 0.1 then time = 0.1 end

	obj:ChangeDirToPos(jumpDownPos)


	local topPos = Vector3((pos.x + jumpDownPos.x) / 2 ,topY,0)
	btObjectView:StartJump(jumpDownPos,topPos,time)
	self._endTime = self:GetTime() + time
end

function LFightIdlePathActor:CalcMoveAndJump(nowPos,nowMinPos,nowMaxPos,nextMinPos,nextMaxPos)
	return LFightIdleConst.CalcMoveAndJump(nowPos,nowMinPos,nowMaxPos,nextMinPos,nextMaxPos)
end

function LFightIdlePathActor:StopPathing()
	if(not self._isPathing) then return end

	self._obj:SetTargetBoardRefId(nil)

	self._isPathing = false
	self._bWaitStopPathing = false

	local btObjectView = self._obj:GetBtObjectView()
	btObjectView:StopMove()
end

function LFightIdlePathActor:WaitStopPathing()
	if not self._isPathing then return end

	self._bWaitStopPathing = true
	if self:IsJumping() then return end
	self:StopPathing()
end

function LFightIdlePathActor:IsPathing()
	return self._isPathing
end

function LFightIdlePathActor:IsJumping()
	return self._isJumping
end

function LFightIdlePathActor:GetTime()
	return self._manager:GetTime()
end

function LFightIdlePathActor:Destroy()
	self._obj = nil
end

return LFightIdlePathActor